class Solution:
    def countDigits(self, num):
        temp = num
        count = 0
        while temp > 0:
            d = temp % 10
            temp //= 10
            if d != 0 and num % d == 0:
                count += 1
        return count

solutions.python:
class Solution:
    def countDigits(self, num):
        count = 0
        for ch in str(num):
            d = int(ch)
            if num % d == 0:
                count += 1
        return count

